1	export type Item = { type: string };
2	
3	export type QuoteStep = { op: "quote"; items: Item[] };
4	
5	export type Step = QuoteStep;
6	
7	export type Scenario = {
8	  customer: { yearsWithMHPCO: number };
9	  steps: Step[];
10	};
11	
12	export type QuoteResult = { premium: number };
13	
14	export type ScenarioResult = {
15	  results: QuoteResult[];
16	};
17	
18	const PROCESSING_FEE = 5;
19	
20	const BASE_PREMIUMS: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	  moonstone: 25,
27	};
28	
29	const RUNE_BLOCK_SIZE = 3;
30	const RUNE_BLOCK_PRICE = 60;
31	
32	const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
33	
34	const runeTotal = (runeCount: number): number =>
35	  runeCount === RUNE_BLOCK_SIZE
36	    ? RUNE_BLOCK_PRICE
37	    : runeCount * BASE_PREMIUMS.rune;
38	
39	const sumBasePremiums = (items: Item[]): number => {
40	  const runes = items.filter((i) => i.type === "rune");
41	  const others = items.filter((i) => i.type !== "rune");
42	  const othersTotal = others.reduce((sum, item) => sum + basePremium(item), 0);
43	  return othersTotal + runeTotal(runes.length);
44	};
45	
46	const quote = ({ items }: QuoteStep): QuoteResult => ({
47	  premium: sumBasePremiums(items) + PROCESSING_FEE,
48	});
49	
50	export const runScenario = (scenario: Scenario): ScenarioResult => ({
51	  results: scenario.steps.map(quote),
52	});
53

